import React from "react"
import "./THEOplayerWrapper.css"

class Player extends React.Component {
  _player = null
  _el = React.createRef()

  componentDidMount() {
    // props like the source, or the sourcedesciption as a whole can be passed through
    // the can then be used to be called on the player itself
    const { source, onPlay } = this.props

    if (this._el.current) {
      this._player = new window.THEOplayer.Player(this._el.current, {
        libraryLocation:
          "https://cdn.myth.theoplayer.com/57e6cd06-50cc-4551-a67f-ea1a2de20219",
        license:
          "sZP7IYe6T6PK3QhL0Sai0Ozc0L3eFSarCoC-CSbZ3Ozc3u5Z3laoIKI63lh6FOPlUY3zWokgbgjNIOf9flft0LxK3SfkFSP1CK0-3uAKCZk10SIlFSC_0uI13S5t3lIeTOfVfK4_bQgZCYxNWoryIQXzImf90SCc3Lbi0Lfi0u5i0Oi6Io4pIYP1UQgqWgjeCYxgflEc3lBZ3u0ZTuR_0lecFOPeWok1dDrLYtA1Ioh6TgV6UQ1gWtAVCYggb6rlWoz6FOPVWo31WQ1qbta6FOPtbwPpImr_sYE6Ymi6IQj-CDgpbkjLWt4ZCoh6TgV6UQ1gWtAVCYggb6rlWoz6FOPVWo31WQ1qbta6FOfJfgzVfG3edt06TgV6dwx-Wuh6Ymi6bo4pIXjNWYAZIY3LdDjpflNzbG4gya"
      })

      this._player.source = source
      this._player.addEventListener("play", onPlay)
    }
  }

  componentWillUnmount() {
    if (this._player) {
      this._player.destroy()
    }
  }

  render() {
    return (
      <div
        // vjs-16-9 THEOplayer are not necessary, but just added for demo purposes
        className={
          "theoplayer-container video-js theoplayer-skin vjs-16-9 THEOplayer"
        }
        // The ref prop here is key it returns the actual dom element and not the virtual react dom elements
        // Which is need by the player
        ref={this._el}
      />
    )
  }
}

export default Player
